mapper.select:
SELECT
,
jiaoshi.jiaoshi_name as jiaoshiName,
jiaoshi.jiaoshi_photo as jiaoshiPhoto,
jiaoshi.jiaoshi_id_number as jiaoshiIdNumber,
jiaoshi.jiaoshi_phone as jiaoshiPhone,
jiaoshi.jiaoshi_email as jiaoshiEmail,
jiaoshi.jiaoshi_delete as jiaoshiDelete,
kecheng.kecheng_name as kechengName,
chapter.chapter_name as chapterName
FROM zuoye a
LEFT JOIN jiaoshi jiaoshi ON a.jiaoshi_id = jiaoshi.id
LEFT JOIN kecheng kecheng ON a.kecheng_id = kecheng.id
LEFT JOIN course_chapter chapter ON a.chapter_id = chapter.id


        and a.id in

            #{item}



        and a.zuoye_name like CONCAT('%',#{params.zuoyeName},'%')


        and a.zuoye_types = #{params.zuoyeTypes}


        and a.jiaoshi_id = #{params.jiaoshiId}


        and a.kecheng_id = #{params.kechengId}


        and a.chapter_id = #{params.chapterId}


        and a.publish_status = #{params.publishStatus}


        and a.question_ids = #{params.questionIds}


        and a.zuoye_content like CONCAT('%',#{params.zuoyeContent},'%')


         and a.zuoye_delete >= #{params.zuoyeDeleteStart} 


         and a.zuoye_delete <= #{params.zuoyeDeleteEnd} 


        and a.zuoye_delete = #{params.zuoyeDelete}


         and UNIX_TIMESTAMP(a.insert_time) >= UNIX_TIMESTAMP(#{params.insertTimeStart}) 


         and UNIX_TIMESTAMP(a.insert_time) <= UNIX_TIMESTAMP(#{params.insertTimeEnd}) 


         and UNIX_TIMESTAMP(a.deadline_time) >= UNIX_TIMESTAMP(#{params.deadlineTimeStart}) 


         and UNIX_TIMESTAMP(a.deadline_time) <= UNIX_TIMESTAMP(#{params.deadlineTimeEnd}) 


        and a.jiaoshi_id IS NOT NULL


        and jiaoshi.jiaoshi_name like CONCAT('%',#{params.jiaoshiName},'%')


        and jiaoshi.jiaoshi_id_number like CONCAT('%',#{params.jiaoshiIdNumber},'%')


        and jiaoshi.jiaoshi_phone like CONCAT('%',#{params.jiaoshiPhone},'%')


        and jiaoshi.jiaoshi_email like CONCAT('%',#{params.jiaoshiEmail},'%')


         and jiaoshi.jiaoshi_delete >= #{params.jiaoshiDeleteStart} 


         and jiaoshi.jiaoshi_delete <= #{params.jiaoshiDeleteEnd} 


        and jiaoshi.jiaoshi_delete = #{params.jiaoshiDelete}


order by a.${params.sort} ${params.order}
